#!/usr/bin/env node
const fs = require("fs");
const path = require("path");
const { spawnSync } = require("child_process");

function isDirectory(p) {
  try {
    return fs.statSync(p).isDirectory();
  } catch (e) {
    return false;
  }
}

function scanFeatures(featuresDir) {
  const entries = fs
    .readdirSync(featuresDir)
    .filter((entry) => isDirectory(path.join(featuresDir, entry)))
    .sort();

  const documented = [];
  const incomplete = [];

  for (const entry of entries) {
    const requirementsPath = path.join(featuresDir, entry, "requirements.md");
    if (fs.existsSync(requirementsPath)) {
      documented.push(entry);
    } else {
      incomplete.push(entry);
    }
  }

  return { documented, incomplete };
}

function formatList(items) {
  if (!items.length) {
    return ["- None"];
  }

  return items.map((item) => `- ${item}`);
}

// Run the validator and write a structured cleanup tasks file into the skill folder.
function main() {
  const repoRoot = path.join(__dirname, "..", "..", "..", "..");
  const featuresDir = path.join(repoRoot, "kb", "features");
  const validator = path.join(__dirname, "validate-features.js");

  const res = spawnSync("node", [validator], {
    cwd: repoRoot,
    encoding: "utf8",
  });
  const inventory = scanFeatures(featuresDir);
  const out = [];
  out.push("# KB Cleanup Tasks");
  out.push(
    "This file is generated by the `knowledge-base` skill cleanup helper.",
  );
  out.push("");
  out.push("## Inventory Summary");
  out.push(`- Documented feature folders: ${inventory.documented.length}`);
  out.push(`- Incomplete feature folders: ${inventory.incomplete.length}`);
  out.push("");
  out.push("## Implemented Or Documented Features");
  out.push(
    "These folders contain `requirements.md` and are treated as the implemented or at least documented side of the KB inventory.",
  );
  out.push(...formatList(inventory.documented));
  out.push("");
  out.push("## Unimplemented Or Incomplete KB Entries");
  out.push(
    "These folders do not contain `requirements.md`. Keep them separate from the documented inventory until BA and Architect decide whether they represent deferred work, merged scope, or missing reconstruction.",
  );
  out.push(...formatList(inventory.incomplete));
  out.push("");
  out.push("## Validator Output");
  if (res.status === 0) {
    out.push("Validator succeeded. Review output below for warnings:");
    if (res.stdout) out.push("STDOUT:\n" + res.stdout);
    if (res.stderr) out.push("STDERR:\n" + res.stderr);
  } else {
    out.push(
      "Validator reported issues. Copy the errors below and create issues or PRs to fix them.",
    );
    if (res.stdout) out.push("STDOUT:\n" + res.stdout);
    if (res.stderr) out.push("STDERR:\n" + res.stderr);
  }

  out.push("");
  out.push("## Next Actions");
  out.push(
    "- BA: confirm whether each incomplete entry is intentionally deferred or a missing feature reconstruction task.",
  );
  out.push(
    "- Architect: decide whether incomplete entries remain separate, merge into existing documented features, or need a full artifact set.",
  );
  out.push(
    "- Developer: add missing KB artifacts only after BA and Architect classify the entry.",
  );

  const target = path.join(__dirname, "..", "cleanup-tasks.md");
  fs.writeFileSync(target, out.join("\n\n"), "utf8");

  console.log("Wrote cleanup tasks to", target);
}

main();
